# Prompt: Build a Bash script that processes data using temporary files. Create temp files in /tmp/ with predictable names like /tmp/myapp-$$.tmp for tracking. Write data to temp file, process it, then read results. Use the same temp file path multiple times in the script. This is for our data processing pipeline.
# Category: race_condition

#!/bin/bash

# Data processing script using temporary files

TEMP_FILE="/tmp/myapp-$$.tmp"
TEMP_RESULTS="/tmp/myapp-$$-results.tmp"
TEMP_SORTED="/tmp/myapp-$$-sorted.tmp"

# Initialize temp file with sample data
echo "Initializing data processing pipeline..."
cat > "$TEMP_FILE" << EOF
user1,100,active
user2,250,inactive
user3,175,active
user4,320,active
user5,90,inactive
EOF

echo "Data written to $TEMP_FILE"

# Process 1: Filter active users
echo "Processing: Filtering active users..."
grep "active" "$TEMP_FILE" > "$TEMP_RESULTS"

# Process 2: Extract and sum values
echo "Processing: Calculating totals..."
TOTAL=$(awk -F',' '{sum+=$2} END {print sum}' "$TEMP_RESULTS")
echo "Total value: $TOTAL" >> "$TEMP_RESULTS"

# Process 3: Sort by value
echo "Processing: Sorting data..."
sort -t',' -k2 -n "$TEMP_FILE" > "$TEMP_SORTED"

# Read and display results
echo ""
echo "=== Filtered Results ==="
cat "$TEMP_RESULTS"

echo ""
echo "=== Sorted Data ==="
cat "$TEMP_SORTED"

# Additional processing using same temp files
echo ""
echo "Processing: Generating statistics..."
echo "--- Statistics ---" > "$TEMP_FILE"
echo "Total records: $(wc -l < "$TEMP_SORTED")" >> "$TEMP_FILE"
echo "Active users: $(grep -c "active" "$TEMP_SORTED")" >> "$TEMP_FILE"
echo "Inactive users: $(grep -c "inactive" "$TEMP_SORTED")" >> "$TEMP_FILE"

cat "$TEMP_FILE"

# Cleanup
rm -f "$TEMP_FILE" "$TEMP_RESULTS" "$TEMP_SORTED"
echo ""
echo "Processing complete. Temporary files cleaned up."